import{_ as a,o as d,c as t,a2 as s}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"الإعداد (Configuration)","description":"","frontmatter":{},"headers":[],"relativePath":"ar/guide/configuration.md","filePath":"ar/guide/configuration.md"}'),i={name:"ar/guide/configuration.md"};function o(c,e,n,r,l,p){return d(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="الإعداد-configuration" tabindex="-1">الإعداد (Configuration) <a class="header-anchor" href="#الإعداد-configuration" aria-label="Permalink to &quot;الإعداد (Configuration)&quot;">​</a></h1><p>تأتي Clearance مع قيم افتراضية منطقية، لذا تعمل مباشرة بعد <a href="/clearance-docs/ar/guide/installation.html">التثبيت</a>. انشر ملف الإعداد عندما تحتاج إلى تخصيص بادئة المسار (route prefix)، أو الـ middleware، أو النماذج السياقية، أو أي إعداد آخر.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>هذا ينشر <code>config/clearance.php</code>.</p><h2 id="مرجع-الإعدادات" tabindex="-1">مرجع الإعدادات <a class="header-anchor" href="#مرجع-الإعدادات" aria-label="Permalink to &quot;مرجع الإعدادات&quot;">​</a></h2><p>هذا هو المرجع النهائي لكل مفتاح في <code>config/clearance.php</code>. الصفحات الأخرى في هذه الوثائق تُحيل إلى هنا بدلاً من تكرار الجدول.</p><table tabindex="0"><thead><tr><th>المفتاح</th><th>القيمة الافتراضية</th><th>الغرض</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>بادئة الـ URI لجميع مسارات اللوحة.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>تُطبَّق على جميع مسارات اللوحة قبل <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>الصلاحية التي يتحقق منها middleware الوصول.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>تُستخدم <code>auth.providers.users.model</code> افتراضياً.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>المفتاح الرئيسي لوحدة المستخدمين (المسارات + مكوّنات Livewire).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - النماذج التي يمكن أن تعمل كسياقات مرتبطة بالأدوار.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>فرض تسمية الصلاحيات بصيغة <code>group-action</code>.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>حرف الفصل - <code>&#39;-&#39;</code> أو <code>&#39;_&#39;</code> فقط.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>تجاوز الحراس المكتشَفين تلقائياً من <code>config/auth.php</code>. فارغ = اكتشاف الكل تلقائياً.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>المحركات (drivers) المقبولة عند حقن حراس قاعدة البيانات في <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>تخطيط Blade للمكوّنات ذات الصفحة الكاملة. <code>null</code> = الافتراضي الخاص بالتطبيق المضيف (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>تعيين الدور الافتراضي المُهيّأ في الإعدادات تلقائياً عند حدث <code>Registered</code>.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>اختياري: يتجاوز <code>super_admin</code> جميع فحوصات Gate على مستوى التطبيق بأكمله.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = اكتشاف تلقائي عبر <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="اصطلاح-تسمية-الصلاحيات" tabindex="-1">اصطلاح تسمية الصلاحيات <a class="header-anchor" href="#اصطلاح-تسمية-الصلاحيات" aria-label="Permalink to &quot;اصطلاح تسمية الصلاحيات&quot;">​</a></h2><p>يجب أن تتبع الصلاحيات صيغة <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>عطّل الفرض حسب البيئة عبر <code>enforce_naming_convention</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">يتم التحقق من الفاصل عند الإقلاع</p><p>قيمة <code>naming_separator</code> هي الجزء الوحيد من هذا الإعداد الذي يصل إلى جزء SQL خام (تجميع/فرز الصلاحيات)، لذا لا يُقبل سوى <code>-</code> أو <code>_</code>.</p></div><h2 id="تخصيص-الـ-middleware" tabindex="-1">تخصيص الـ Middleware <a class="header-anchor" href="#تخصيص-الـ-middleware" aria-label="Permalink to &quot;تخصيص الـ Middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>تبقى أسماء المسارات (route names) ثابتة بغض النظر عن تغييرات البادئة أو الـ middleware - انظر <a href="/clearance-docs/ar/guide/quick-start.html">البدء السريع</a> للاطلاع على جدول المسارات الكامل.</p><h2 id="ذو-صلة" tabindex="-1">ذو صلة <a class="header-anchor" href="#ذو-صلة" aria-label="Permalink to &quot;ذو صلة&quot;">​</a></h2><ul><li><a href="/clearance-docs/ar/guide/quick-start.html">البدء السريع</a> - تركيب اللوحة مع تطبيق هذه الإعدادات</li><li><a href="/clearance-docs/ar/guide/publishing.html">نشر الأصول</a> - نشر الترجمات وفهم مفتاح <code>layout</code></li><li><a href="/clearance-docs/ar/features/guards.html">الحراس</a> - كيفية استخدام <code>guards</code> و<code>allowed_guard_drivers</code></li><li><a href="/clearance-docs/ar/features/super-admin.html">المشرف الفائق</a> - كيف يعمل <code>super_admin_gate_bypass</code></li></ul>`,18)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
